external_knowledge:
- "blockbuster movies" refers to highly successful movies with high revenue; 
- "soaring fortunes" means achieving significant revenue; 
- "turn of the millennium" refers to the year 2000; 
- "broken even" means having a positive revenue; 
- "treasure chests" metaphorically refers to the total worldwide revenue.

sql:
SELECT SUM(spend_amount) AS total_spent
FROM marketing_spends
WHERE movie_id = 1;

SELECT movie_id, revenue_type_id, SUM(revenue_amount) AS total_revenue
FROM movie_revenues
GROUP BY movie_id, revenue_type_id;

SELECT COUNT(*) AS file_count
FROM movie_files
WHERE movie_id = 0;

SELECT MAX(total_spend) AS highest_spent_movie
FROM (
    SELECT movie_id, SUM(spend_amount) AS total_spend
    FROM marketing_spends
    GROUP BY movie_id
) AS movie_spending;

SELECT 
  (SELECT SUM(revenue_amount) FROM movie_revenues WHERE movie_id = 1) -
  (SELECT SUM(spend_amount) FROM marketing_spends WHERE movie_id = 1) AS net_revenue;

SELECT MAX(spend_amount) AS max_spend_amount
FROM marketing_spends
WHERE movie_id = 1;

SELECT title
FROM movies
WHERE year = 2019;

SELECT movie_id, spend_channel, spend_amount
FROM marketing_spends
WHERE spend_date LIKE '2019%';
